code.C:
#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long M, R;
        scanf("%lld %lld", &M, &R);
        long long K = R - 1;
        printf("%lld\n", K % 1000000007);
    }
    return 0;
}

